const json = item.json ?? {};

function normalizeDesignText(payload) {
  if (payload && typeof payload === "object") {
    return JSON.stringify(payload, null, 2);
  }
  if (typeof payload === "string" && payload.trim()) {
    const parsed = JSON.parse(payload);
    return JSON.stringify(parsed, null, 2);
  }
  return "";
}

const response = normalizeDesignText(json.designJson ?? json.response);
if (!response) {
  throw new Error("Design JSON is missing before review ZIP creation.");
}

const parsedTokens = Number(json.outputTokens);
const outputTokens = Number.isFinite(parsedTokens) && parsedTokens >= 0
  ? Math.trunc(parsedTokens)
  : Math.max(1, Math.round(response.length / 4));

const outputTokensSource = String(json.outputTokensSource ?? "estimated_char_div4").trim() || "estimated_char_div4";

function makeBinaryText(text, fileName, mimeType) {
  return {
    data: Buffer.from(String(text), "utf8").toString("base64"),
    fileName,
    mimeType,
  };
}

const binary = {
  ...(item.binary ?? {}),
  designSpec: makeBinaryText(response, "design_draft.json", "application/json"),
  outTokens: makeBinaryText(`${outputTokens}\n`, "out_tokens.txt", "text/plain"),
};

return [{
  json: {
    ...json,
    response,
    designJson: JSON.parse(response),
    outputTokens,
    outputTokensSource,
  },
  binary,
}];

