import base64
import io
import json
import math
import re
import zipfile
from PIL import Image, ImageColor, ImageDraw, ImageFont

CANVAS_BG = "#F7F7F7"
DEFAULT_STROKE = "#1f2937"
DEFAULT_FILL = "#ffffff"


def _to_number(value, default=0.0):
    try:
        return float(value)
    except Exception:
        return float(default)


def _read_binary_text(binary_entry):
    if not isinstance(binary_entry, dict):
        return ""
    raw = binary_entry.get("data")
    if not raw:
        return ""
    try:
        return base64.b64decode(str(raw)).decode("utf8").strip()
    except Exception:
        return ""


def _safe_name(value, fallback="item"):
    text = str(value or "").strip() or fallback
    text = re.sub(r"[^A-Za-z0-9._-]+", "_", text)
    text = text.strip("._-")
    return text or fallback


def _element_bounds(el):
    x = _to_number(el.get("x"), 0.0)
    y = _to_number(el.get("y"), 0.0)
    w = _to_number(el.get("width"), _to_number(el.get("w"), 0.0))
    h = _to_number(el.get("height"), _to_number(el.get("h"), 0.0))

    points = el.get("points")
    if isinstance(points, list) and points:
        pxs = []
        pys = []
        for p in points:
            if isinstance(p, (list, tuple)) and len(p) >= 2:
                pxs.append(x + _to_number(p[0]))
                pys.append(y + _to_number(p[1]))
        if pxs and pys:
            min_x = min(pxs)
            min_y = min(pys)
            max_x = max(pxs)
            max_y = max(pys)
            x, y = min_x, min_y
            w, h = max_x - min_x, max_y - min_y

    return {
        "x": float(x),
        "y": float(y),
        "w": max(0.0, float(w)),
        "h": max(0.0, float(h)),
    }


def _intersects(a, b):
    return not (
        a["x"] + a["w"] < b["x"]
        or a["x"] > b["x"] + b["w"]
        or a["y"] + a["h"] < b["y"]
        or a["y"] > b["y"] + b["h"]
    )


def _overall_bbox(elements):
    xs = []
    ys = []
    x2 = []
    y2 = []
    for el in elements:
        if not isinstance(el, dict) or el.get("isDeleted"):
            continue
        b = _element_bounds(el)
        xs.append(b["x"])
        ys.append(b["y"])
        x2.append(b["x"] + max(1.0, b["w"]))
        y2.append(b["y"] + max(1.0, b["h"]))

    if not xs:
        return {"x": 0.0, "y": 0.0, "w": 1200.0, "h": 800.0}

    return {
        "x": min(xs),
        "y": min(ys),
        "w": max(x2) - min(xs),
        "h": max(y2) - min(ys),
    }


def _collect_frames(elements):
    frames = []
    for idx, el in enumerate(elements):
        if not isinstance(el, dict) or el.get("isDeleted"):
            continue
        if str(el.get("type") or "").strip().lower() != "frame":
            continue
        b = _element_bounds(el)
        if b["w"] <= 1.0 or b["h"] <= 1.0:
            continue
        frames.append(
            {
                "id": str(el.get("id") or f"frame_{idx + 1}"),
                "name": str(el.get("name") or el.get("label") or f"Frame {idx + 1}"),
                "bbox": b,
            }
        )

    return frames


def _pick_font(size):
    size = max(8, int(size))
    for path in (
        "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
        "/usr/share/fonts/TTF/DejaVuSans.ttf",
    ):
        try:
            return ImageFont.truetype(path, size=size)
        except Exception:
            continue
    return ImageFont.load_default()


def _to_rgba(value, alpha=255, fallback="#000000"):
    color = str(value or fallback).strip()
    if color.lower() in ("", "none", "transparent"):
        return (0, 0, 0, 0)
    try:
        rgb = ImageColor.getrgb(color)
    except Exception:
        rgb = ImageColor.getrgb(fallback)

    if len(rgb) == 4:
        return (rgb[0], rgb[1], rgb[2], int(max(0, min(255, alpha))))
    return (rgb[0], rgb[1], rgb[2], int(max(0, min(255, alpha))))


def _render_png(elements, bbox, padding=24.0):
    px = float(bbox["x"]) - float(padding)
    py = float(bbox["y"]) - float(padding)
    pw = max(1.0, float(bbox["w"]) + 2.0 * float(padding))
    ph = max(1.0, float(bbox["h"]) + 2.0 * float(padding))

    width = int(math.ceil(pw))
    height = int(math.ceil(ph))

    ox = -px
    oy = -py

    img = Image.new("RGBA", (width, height), _to_rgba(CANVAS_BG))
    draw = ImageDraw.Draw(img, "RGBA")

    for el in elements:
        if not isinstance(el, dict) or el.get("isDeleted"):
            continue

        et = str(el.get("type") or "").lower()
        b = _element_bounds(el)
        x = b["x"] + ox
        y = b["y"] + oy
        w = b["w"]
        h = b["h"]

        opacity = max(0.0, min(1.0, _to_number(el.get("opacity"), 100.0) / 100.0))
        alpha = int(opacity * 255)
        sw = max(1, int(round(_to_number(el.get("strokeWidth"), 1.0))))

        stroke = _to_rgba(el.get("strokeColor"), alpha=alpha, fallback=DEFAULT_STROKE)
        fill = _to_rgba(el.get("backgroundColor"), alpha=alpha, fallback=DEFAULT_FILL)
        if str(el.get("backgroundColor") or "").lower() in ("", "none", "transparent"):
            fill = (0, 0, 0, 0)

        if et in ("rectangle", "frame"):
            x2 = x + w
            y2 = y + h
            radius = 8 if el.get("roundness") else 0
            if radius > 0:
                draw.rounded_rectangle((x, y, x2, y2), radius=radius, fill=fill, outline=stroke, width=sw)
            else:
                draw.rectangle((x, y, x2, y2), fill=fill, outline=stroke, width=sw)
        elif et == "ellipse":
            draw.ellipse((x, y, x + w, y + h), fill=fill, outline=stroke, width=sw)
        elif et in ("line", "arrow"):
            points = el.get("points")
            if isinstance(points, list) and len(points) >= 2:
                pts = []
                for p in points:
                    if isinstance(p, (list, tuple)) and len(p) >= 2:
                        pts.append((x + _to_number(p[0]), y + _to_number(p[1])))
                if len(pts) >= 2:
                    draw.line(pts, fill=stroke, width=sw)
            else:
                draw.line((x, y, x + w, y + h), fill=stroke, width=sw)
        elif et == "diamond":
            cx = x + w / 2.0
            cy = y + h / 2.0
            pts = [(cx, y), (x + w, cy), (cx, y + h), (x, cy)]
            draw.polygon(pts, fill=fill, outline=stroke)
        elif et == "text":
            text = str(el.get("text") or "")
            if not text:
                continue
            fs = max(8, int(_to_number(el.get("fontSize"), 14)))
            lh = max(10, int(fs * 1.25))
            font = _pick_font(fs)
            for i, line in enumerate(text.splitlines() or [""]):
                draw.text((x, y + i * lh), line, fill=stroke, font=font)
        else:
            if w > 0 and h > 0:
                draw.rectangle((x, y, x + w, y + h), fill=fill, outline=stroke, width=sw)

    out = io.BytesIO()
    img.save(out, format="PNG")
    return out.getvalue()


outputs = []
for item in _items:
    src = item.get("json", {}) if isinstance(item, dict) else {}
    in_binary = item.get("binary", {}) if isinstance(item, dict) and isinstance(item.get("binary"), dict) else {}

    out_json = dict(src)
    out_binary = dict(in_binary)

    try:
        raw_design = src.get("designJson")
        if raw_design is None:
            raw_design = src.get("design")
        if raw_design is None:
            raw_design = src.get("response")

        if isinstance(raw_design, dict):
            design = raw_design
        elif isinstance(raw_design, str):
            design = json.loads(raw_design)
        else:
            raise ValueError("Design JSON payload is missing.")

        elements = design.get("elements")
        if not isinstance(elements, list):
            raise ValueError("Design JSON is invalid: missing elements list.")

        overview_bbox = _overall_bbox(elements)
        frames = _collect_frames(elements)

        if not frames:
            frames = [
                {
                    "id": "canvas",
                    "name": "Canvas",
                    "bbox": overview_bbox,
                }
            ]

        manifest_assets = []

        zip_buffer = io.BytesIO()
        with zipfile.ZipFile(zip_buffer, "w", zipfile.ZIP_DEFLATED) as zf:
            overview_png = _render_png(elements, overview_bbox, padding=32.0)
            zf.writestr("overview.png", overview_png)
            manifest_assets.append(
                {
                    "id": "overview",
                    "name": "Overview",
                    "type": "overview",
                    "path": "overview.png",
                    "bbox": overview_bbox,
                    "elementCount": len(elements),
                }
            )

            for frame in frames:
                fb = frame["bbox"]
                padded = {
                    "x": float(fb["x"]) - 6.0,
                    "y": float(fb["y"]) - 6.0,
                    "w": float(fb["w"]) + 12.0,
                    "h": float(fb["h"]) + 12.0,
                }

                subset = [
                    el for el in elements
                    if isinstance(el, dict) and _intersects(_element_bounds(el), padded)
                ]

                png_bytes = _render_png(subset or elements, padded, padding=20.0)
                path = f"screens/{_safe_name(frame['name'], frame['id'])}.png"
                zf.writestr(path, png_bytes)

                manifest_assets.append(
                    {
                        "id": frame["id"],
                        "name": frame["name"],
                        "type": "frame",
                        "path": path,
                        "bbox": padded,
                        "elementCount": len(subset),
                    }
                )

            output_tokens = int(_to_number(src.get("outputTokens"), 0))
            if output_tokens <= 0:
                out_tokens_binary = in_binary.get("outTokens")
                parsed_text = _read_binary_text(out_tokens_binary)
                output_tokens = int(_to_number(parsed_text, 0))

            if output_tokens > 0:
                zf.writestr("out_tokens.txt", f"{output_tokens}\n")

        zip_bytes = zip_buffer.getvalue()
        revision = int(_to_number(src.get("revisionNumber"), 0))
        zip_name = "design.zip"

        out_binary["reviewZip"] = {
            "data": base64.b64encode(zip_bytes).decode("ascii"),
            "mimeType": "application/zip",
            "fileName": zip_name,
            "fileExtension": "zip",
            "fileSize": str(len(zip_bytes)),
        }

        out_json["archiveData"] = base64.b64encode(zip_bytes).decode("ascii")
        out_json["archiveId"] = ""

        out_json["designAssetCount"] = len(manifest_assets)
        out_json["designAssetManifest"] = {
            "counts": {
                "images": len(manifest_assets),
                "frames": max(0, len(manifest_assets) - 1),
            },
            "assets": manifest_assets,
        }
        out_json.pop("designAssetError", None)
    except Exception as err:
        out_json["designAssetCount"] = 0
        out_json["designAssetError"] = str(err)

    outputs.append({"json": out_json, "binary": out_binary})

return outputs

